import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Tokyo",
    temperature = 28,
    condition = "Sunny",
    humidity = 45,
    windSpeed = 8,
    unit = "C",
    forecast = [
      { day: "Mon", icon: "☀️", high: 30, low: 22 },
      { day: "Tue", icon: "⛅", high: 27, low: 20 },
    ],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={16}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>{city}</Heading>
          <Text variant="label">{condition}</Text>
        </Stack>

        <Stack gap={0} align="center">
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}°{unit}
          </Heading>
        </Stack>

        <Stack direction="horizontal" justify="around" gap={16}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
            <Text variant="body" weight="semibold">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
            <Text variant="body" weight="semibold">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={4} style={{ flex: 1 }}>
              <Text variant="caption">{item.day || '-'}</Text>
              <Text size="xl">{item.icon || '?'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="bodySmall" weight="semibold">{item.high !== undefined ? `${item.high}°` : '-'}</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{item.low !== undefined ? `${item.low}°` : '-'}</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Box } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: any) => void;
}

export default function SurveyForm({
  featureOptions = [
    "Dashboard Analytics",
    "Team Collaboration",
    "API Integration",
    "Custom Workflows",
    "Mobile App",
    "AI Assistance"
  ],
  satisfactionLabels = [
    "Very Unsatisfied",
    "Unsatisfied",
    "Neutral",
    "Satisfied",
    "Very Satisfied"
  ],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const totalSteps = 5;
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: null as number | null,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction !== null;
    return true;
  };

  const handleNext = () => {
    if (step === 1) {
      const newErrors = {
        name: formData.name.trim() === '' ? 'Name is required' : '',
        email: !validateEmail(formData.email) ? 'Valid email is required' : ''
      };
      setErrors(newErrors);
      if (newErrors.name || newErrors.email) return;
    }
    setStep(s => Math.min(s + 1, totalSteps));
  };

  const handleBack = () => setStep(s => Math.max(s - 1, 1));

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        <Heading level={2}>Survey</Heading>
        <Stack direction="horizontal" gap={8} align="center" justify="between">
          <Text variant="caption">Step {step} of {totalSteps}</Text>
          <Progress value={(step / totalSteps) * 100} size="sm" />
        </Stack>

        <Box paddingY={8}>
          {step === 1 && (
            <Stack gap={12}>
              <Input 
                label="Name"
                required 
                value={formData.name} 
                onChange={(v) => {
                  setFormData(p => ({ ...p, name: v }));
                  if (errors.name) setErrors(p => ({ ...p, name: '' }));
                }} 
                error={errors.name} 
              />
              <Input 
                label="Email"
                required 
                type="email" 
                value={formData.email} 
                onChange={(v) => {
                  setFormData(p => ({ ...p, email: v }));
                  if (errors.email) setErrors(p => ({ ...p, email: '' }));
                }} 
                error={errors.email} 
              />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="Satisfaction Rating"
              value={formData.satisfaction?.toString() || ''}
              onChange={(v) => setFormData(p => ({ ...p, satisfaction: parseInt(v) }))}
              options={satisfactionLabels.map((label, i) => ({ value: (i + 1).toString(), label }))}
            />
          )}

          {step === 3 && (
            <Stack gap={8}>
              <Text variant="label">Feature Interests</Text>
              {featureOptions.map(f => (
                <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => toggleFeature(f)} />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea
              label="Comments"
              value={formData.comments}
              onChange={(v) => setFormData(p => ({ ...p, comments: v }))}
              maxLength={500}
              showCount
            />
          )}

          {step === 5 && (
            <Stack gap={8}>
              <Heading level={4}>Review</Heading>
              <Text variant="bodySmall">Name: {formData.name}</Text>
              <Text variant="bodySmall">Email: {formData.email}</Text>
              <Text variant="bodySmall">Satisfaction: {formData.satisfaction ? satisfactionLabels[formData.satisfaction - 1] : 'N/A'}</Text>
              <Text variant="bodySmall">Features: {formData.features.join(', ') || 'None'}</Text>
              <Text variant="bodySmall">Comments: {formData.comments || 'No comments'}</Text>
            </Stack>
          )}
        </Box>

        <Stack direction="horizontal" gap={8} justify="between">
          <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < totalSteps ? (
            <Button onClick={handleNext} disabled={!isStepValid()}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit({
              name: formData.name,
              email: formData.email,
              satisfaction: formData.satisfaction,
              features: formData.features,
              comments: formData.comments
            })}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Button, Input, Select, Badge, Avatar, Box } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Array<Task>;
  columns: Array<Column>;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent({ tasks = [], columns = [], onTaskUpdate }: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Task['priority']>('medium');

  const handleUpdate = (action: string, taskId: string, data: any) => {
    const updatedTasks = localTasks.map(t => (t.id === taskId ? { ...t, ...data } : t));
    setLocalTasks(updatedTasks);
    onTaskUpdate?.({ action, taskId, data });
  };

  const handleCreate = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??',
    };
    setLocalTasks([...localTasks, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id!, data: newTask });
    setNewTaskTitle('');
    setAddingTo(null);
  };

  const totalTasks = localTasks.length;
  const doneTasks = localTasks.filter(t => t.column === 'done').length;

  const getPriorityBadge = (p?: string) => {
    const variants: Record<string, 'success' | 'warning' | 'error'> = {
      low: 'success',
      medium: 'warning',
      high: 'error',
    };
    return <Badge variant={variants[p || 'medium'] || 'default'}>{p}</Badge>;
  };

  return (
    <Box padding={24}>
      <Stack gap={24}>
        <Card padding={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="bodyLarge" weight="bold">Kanban Board</Text>
            <Text variant="bodySmall">Total: {totalTasks} | Done: {doneTasks}</Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={16} align="start">
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" borderRadius={8} padding={16} style={{ flex: 1, minWidth: 280 }}>
              <Stack gap={16}>
                <Text variant="label" weight="semibold">
                  {col.name} ({localTasks.filter(t => t.column === col.id).length})
                </Text>

                <Stack gap={12}>
                  {localTasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12}>
                      <Stack gap={8}>
                        <Text weight="medium">{task.title}</Text>
                        <Stack direction="horizontal" justify="between" align="center">
                          {getPriorityBadge(task.priority)}
                          <Avatar name={task.assignee || '??'} size={24} />
                        </Stack>
                        <Select
                          label="Move to"
                          value={task.column}
                          onChange={(val) => handleUpdate('move', task.id!, { column: val })}
                          options={columns.map(c => ({ value: c.id!, label: c.name! }))}
                          size="sm"
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingTo === col.id ? (
                  <Card padding={12}>
                    <Stack gap={8}>
                      <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={(v) => setNewTaskPriority(v as any)}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Stack direction="horizontal" gap={8}>
                        <Button size="sm" onClick={() => handleCreate(col.id!)}>Add</Button>
                        <Button size="sm" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" size="sm" onClick={() => setAddingTo(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Input, 
  Box, 
  Divider 
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements?: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-success-200)',
  'noble-gas': 'var(--ggui-color-info-200)',
  'alkali-metal': 'var(--ggui-color-primary-200)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-100)',
  'transition-metal': 'var(--ggui-color-warning-100)',
  'halogen': 'var(--ggui-color-error-100)',
  'metal': 'var(--ggui-color-neutral-200)',
  'metalloid': 'var(--ggui-color-neutral-300)',
  'lanthanide': 'var(--ggui-color-neutral-100)',
  'actinide': 'var(--ggui-color-neutral-100)',
  'unknown': 'var(--ggui-color-neutral-100)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = elements.filter(
    (el) =>
      el.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map((e) => e.category || 'unknown')));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={1}>Periodic Table</Heading>

        <Box style={{ maxWidth: '400px' }}>
          <Input
            label="Search Elements"
            type="search"
            placeholder="Search by name or symbol..."
            value={searchTerm}
            onChange={setSearchTerm}
          />
        </Box>

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-2, 8px)'
          }}
        >
          {elements.map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <div
                key={el.atomicNumber}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  cursor: 'pointer',
                }}
                onClick={() => setSelectedElement(el)}
              >
                <Card
                  padding="var(--ggui-spacing-2, 8px)"
                  shadow="sm"
                  border={true}
                  radius="sm"
                  style={{
                    backgroundColor: isVisible ? CATEGORY_COLORS[el.category || 'unknown'] || 'var(--ggui-color-surface)' : 'var(--ggui-color-outlineVariant)',
                    opacity: isVisible ? 1 : 0.3,
                    minWidth: '50px',
                    minHeight: '60px',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    transition: 'opacity 0.2s, background-color 0.2s'
                  }}
                >
                  <Text variant="caption" style={{ fontWeight: 600 }}>{el.atomicNumber}</Text>
                  <Text style={{ fontSize: '18px', fontWeight: 'bold', textAlign: 'center' }}>
                    {el.symbol}
                  </Text>
                </Card>
              </div>
            );
          })}
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {categories.map(cat => (
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" key={cat}>
              <Box style={{ width: '16px', height: '16px', borderRadius: '4px', backgroundColor: CATEGORY_COLORS[cat] || 'var(--ggui-color-outline)' }} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
            <Stack gap="var(--ggui-spacing-3, 12px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" wrap>
                <Text variant="body">Symbol: <strong>{selectedElement.symbol}</strong></Text>
                <Text variant="body">Atomic Number: <strong>{selectedElement.atomicNumber}</strong></Text>
                <Text variant="body">Atomic Weight: <strong>{selectedElement.atomicWeight}</strong></Text>
                <Text variant="body">Category: <strong>{selectedElement.category}</strong></Text>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Badge, 
  Divider, 
  Spacer,
  Tabs,
  Icon,
  Table,
  Toast
} from '@ggui-ai/design/primitives';

interface ProductReview {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface ProductSpec {
  key: string;
  value: string;
}

interface Product {
  id: string;
  name: string;
  price: number;
  currency: string;
  rating: number;
  reviewCount: number;
  stock: number;
  description: string;
  specifications: ProductSpec[];
  reviews: ProductReview[];
}

interface Props {
  product: Product;
  onAddToCart: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { product, onAddToCart } = props;
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(false);
  const [showToast, setShowToast] = useState(false);

  const isOutOfStock = product.stock <= 0;
  const isLowStock = product.stock > 0 && product.stock <= 5;

  const handleAddToCart = async () => {
    setLoading(true);
    try {
      await onAddToCart({ productId: product.id, quantity });
      setShowToast(true);
    } finally {
      setLoading(false);
    }
  };

  const renderStars = (rating: number) => {
    return (
      <Stack direction="horizontal" gap={2}>
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon 
            key={star} 
            name={star <= Math.round(rating) ? 'check' : 'x'} 
            size={16} 
            color={star <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'} 
          />
        ))}
      </Stack>
    );
  };

  const tabs = [
    {
      key: 'desc',
      label: 'Description',
      content: <Text variant="body" color="var(--ggui-color-neutral-700)">{product.description}</Text>
    },
    {
      key: 'specs',
      label: 'Specifications',
      content: (
        <Table
          columns={[{ key: 'key', header: 'Property' }, { key: 'value', header: 'Value' }]}
          data={product.specifications.map(s => ({ key: s.key, value: s.value }))}
        />
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap={16}>
          {product.reviews.map((rev, i) => (
            <Card key={i} padding={16} shadow="none" border={true}>
              <Stack gap={8}>
                <Stack direction="horizontal" justify="between">
                  <Text variant="label">{rev.author}</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500)">{rev.date}</Text>
                </Stack>
                {renderStars(rev.rating)}
                <Text variant="bodySmall">{rev.text}</Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      )
    }
  ];

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box 
            padding={48} 
            background="var(--ggui-color-neutral-200)" 
            borderRadius={12} 
            style={{ flex: 1, minWidth: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Heading level={3}>{product.name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">
              {product.currency === 'USD' ? '$' : product.currency} {product.price.toFixed(2)}
            </Text>

            <Stack direction="horizontal" gap={8} align="center">
              {renderStars(product.rating)}
              <Text variant="caption">({product.reviewCount} reviews)</Text>
            </Stack>

            <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
              {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
            </Badge>

            <Divider />

            <Stack direction="horizontal" gap={12} align="center">
              <Button 
                variant="secondary" 
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
                disabled={isOutOfStock || quantity <= 1}
              >
                <Icon name="minus" size={16} />
              </Button>
              <Text variant="body" style={{ width: 40, textAlign: 'center' }}>{quantity}</Text>
              <Button 
                variant="secondary" 
                onClick={() => setQuantity(Math.min(product.stock, quantity + 1))}
                disabled={isOutOfStock || quantity >= product.stock}
              >
                <Icon name="plus" size={16} />
              </Button>

              <Button 
                variant="primary" 
                onClick={handleAddToCart}
                disabled={isOutOfStock || loading}
                loading={loading}
              >
                Add to Cart
              </Button>
            </Stack>
          </Stack>
        </Stack>

        <Divider />

        <Tabs items={tabs} variant="line" />
      </Stack>

      <Toast 
        visible={showToast} 
        variant="success" 
        title="Added to Cart" 
        message={`Successfully added ${quantity} of ${product.name} to your cart.`}
        onClose={() => setShowToast(false)}
      />
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Button, Input, Box, Divider } from '@ggui-ai/design/primitives';
import { FormField } from '@ggui-ai/design/components';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback when user sends a message */
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = "Team Chat",
  currentUser = "You",
  participantCount = 3,
  messages = [],
  onSend,
}: Props) {
  const [chatMessages, setChatMessages] = useState(messages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setChatMessages(messages);
  }, [messages]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const sendMessage = () => {
    if (!inputValue.trim()) return;
    const timestamp = new Date().toISOString();
    const payload = { text: inputValue, timestamp };
    onSend?.(payload);
    setChatMessages((prev) => [...prev, { ...payload, sender: currentUser }]);
    setInputValue('');
  };

  return (
    <Card shadow="md" padding={0} style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', maxWidth: '500px', overflow: 'hidden' }}>
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
        <Stack direction="horizontal" align="center" justify="between">
          <Text variant="label">{title}</Text>
          <Text variant="caption">{participantCount} participants</Text>
        </Stack>
      </Box>
      <Divider margin={0} />
      <Box padding={16} style={{ flex: 1, overflowY: 'auto' }}>
        <div ref={scrollRef}>
          <Stack gap={12}>
            {chatMessages.map((msg, idx) => {
              const isOwn = msg.sender === currentUser;
              return (
                <Stack key={idx} align={isOwn ? 'end' : 'start'} gap={4}>
                  <Box
                    paddingX={12}
                    paddingY={8}
                    borderRadius={12}
