export default function StockTickerDashboard(props: Props) {
  const [stocks, setStocks] = useState<Stock[]>(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    // Contract: Use global event listener for stream data as per spec
    const handleData = (event: any) => {
      if (event.detail) {
        setStocks(event.detail.stocks || []);
        setLastUpdated(event.detail.lastUpdated || new Date().toISOString());
