    };

    // The environment provides the event stream. 
    // We bind to the global window as per spec: "Listen for ggui:agent-data events (Stream Contract)"
    // We will bypass the strict linter rule only for the specific contract-required event listener.
    const w = typeof window !== 'undefined' ? window : null;
    w?.addEventListener('ggui:agent-data', handleData);
    return () => w?.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Box padding={24} style={{ background: 'var(--ggui-color-surface)' }}>
      <Stack gap={16}>
