import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Checkbox, Toggle, Divider, Container } from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  onComplete: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || avatarOptions[0],
    role: initialProfile.role || roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const [errors, setErrors] = useState({ email: '' });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const nextStep = () => {
    if (step === 1 && !validateEmail(formData.email)) {
      setErrors({ email: 'Invalid email format' });
      return;
    }
    setErrors({ email: '' });
    setStep(s => Math.min(s + 1, 3));
  };

  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const renderStep = () => {
    switch(step) {
      case 1: return (
        <Stack gap={16}>
          <Input 
            label="Name *" 
            value={formData.name} 
            onChange={(v) => setFormData({...formData, name: v})} 
          />
          <Input 
            label="Email *" 
            type="email" 
            value={formData.email} 
            error={errors.email} 
            onChange={(v) => {
              setFormData({...formData, email: v});
              if (errors.email) setErrors({ email: '' });
            }} 
          />
          <Text variant="label">Select Avatar</Text>
          <Stack direction="horizontal" gap={8}>
            {avatarOptions.map(a => (
              <Button 
                key={a} 
                variant={formData.avatar === a ? 'primary' : 'outline'} 
                onClick={() => setFormData({...formData, avatar: a})}
              >
                {a}
              </Button>
            ))}
          </Stack>
        </Stack>
      );
      case 2: return (
        <Stack gap={16}>
          <Select 
            label="Role" 
            value={formData.role} 
            onChange={(v) => setFormData({...formData, role: v})} 
            options={roleOptions.map(r => ({ value: r, label: r }))} 
          />
          <Checkbox 
            label="Enable Email Notifications" 
            checked={formData.emailNotifications} 
            onChange={(v) => setFormData({...formData, emailNotifications: v})} 
          />
          <Toggle 
            label={`Theme: ${formData.theme === 'light' ? 'Light' : 'Dark'}`} 
            checked={formData.theme === 'dark'} 
            onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})} 
          />
        </Stack>
      );
      case 3: return (
        <Stack gap={16}>
          <Heading level={4}>Review</Heading>
          <Text>Name: {formData.name}</Text>
          <Text>Email: {formData.email}</Text>
          <Text>Avatar: {formData.avatar}</Text>
          <Text>Role: {formData.role}</Text>
          <Text>Notifications: {formData.emailNotifications ? 'On' : 'Off'}</Text>
          <Text>Theme: {formData.theme}</Text>
        </Stack>
      );
      default: return null;
    }
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24} shadow="md">
        <Stack gap={16}>
          <Heading level={2}>Onboarding - Step {step}/3</Heading>
          {renderStep()}
          <Divider />
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={prevStep}>Back</Button>
            {step < 3 ? (
              <Button disabled={step === 1 && !isStep1Valid} onClick={nextStep}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

