  Divider, 
  Avatar, 
  Badge,
  Icon
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Task[];
  columns: Column[];
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent({ 
  tasks: initialTasks = [], 
  columns = [],
  onTaskUpdate
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addTaskToColumn, setAddTaskToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Task['priority']>('medium');

  const totalTasks = tasks.length;
  const completedCount = tasks.filter(t => t.column === 'done').length;

  const handleMove = (taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    onTaskUpdate?.({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleAddSubmit = () => {
    if (!newTaskTitle || !addTaskToColumn) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: addTaskToColumn
    };
    setTasks(prev => [...prev, newTask]);
    onTaskUpdate?.({ action: 'create', data: newTask });
    setNewTaskTitle('');
    setAddTaskToColumn(null);
  };

  return (
    <Box padding={24}>
      <Stack gap={24}>
        <Card padding={16} shadow="sm">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={3}>Kanban Board</Heading>
            <Text variant="label">Total: {totalTasks} | Completed: {completedCount}</Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={16} align="start" wrap={true}>
          {columns.map(col => (
            <Box key={col.id} style={{ width: 300, minWidth: 300 }}>
              <Card padding={16} shadow="sm">
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={5}>{col.name}</Heading>
                    <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
                  </Stack>
                  <Divider />

                  <Stack gap={12}>
                    {tasks.filter(t => t.column === col.id).map(task => (
                      <Card key={task.id} padding={12} shadow="none" border={true}>
                        <Stack gap={8}>
                          <Text variant="label">{task.title}</Text>
                          <Stack direction="horizontal" justify="between" align="center">
                            <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}>
                              {task.priority}
                            </Badge>
                            {task.assignee && <Avatar name={task.assignee} size={24} />}
                          </Stack>
                          <Select 
                            label="Column"
                            value={task.column!} 
                            onChange={(val) => handleMove(task.id!, val)}
                            options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {addTaskToColumn === col.id ? (
                    <Stack gap={8}>
                      <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title" />
                      <Select 
                        label="Priority"
                        value={newTaskPriority!} 
                        onChange={(v) => setNewTaskPriority(v as any)} 
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Button onClick={handleAddSubmit}>Save</Button>
                    </Stack>
                  ) : (
                    <Button variant="ghost" leftIcon={<Icon name="plus" size={16} />} onClick={() => setAddTaskToColumn(col.id!)}>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}

